function ajustarTelefone(raw) {
  if (!raw) return null;

  let t = raw.toString().replace(/\D/g, "");

  if (t.length === 11) t = "55" + t;
  if (t.length === 10) t = "55" + t;
  if (t.startsWith("55")) return t;
  if (t.startsWith("+")) return t.replace("+", "");

  return t;
}

// ========================================
// Identificar gatilho real (9h ou 10min)
// ========================================
let gatilho = null;

// tenta pegar dos possíveis nodes Set
try {
  gatilho = $('Seta o gatilho').first().json.gatilho || null;
} catch {}

try {
  gatilho = $('Seta o gatilho1').first().json.gatilho || gatilho;
} catch {}

try {
  gatilho = $('Seta o gatilho2').first().json.gatilho || gatilho;
} catch {}

if (!gatilho) {
  // fallback opcional
  gatilho = "10min"; 
}

// Lista final
const filtrados = [];

// ========================================================
// CASO 0 → Execução das 19h (Lembrete do dia anterior)
// ========================================================
if (gatilho === "19h") {
  const agora = new Date();

  // Cria uma data representando "Amanhã"
  const amanha = new Date(agora);
  amanha.setDate(amanha.getDate() + 1);

  // Formata para YYYY-MM-DD (ex: 2025-12-24)
  const dataAmanha = amanha.toISOString().split("T")[0];

  for (const item of items) {
    const lead = item.json;
    const telefone = lead.telefone;
    const reuniao = lead.reuniao_data;

    if (!reuniao) continue;

    // Pega a data da reunião (YYYY-MM-DD)
    const dataReuniao = reuniao.split("T")[0];

    // Se a data da reunião for igual a data de amanhã
    if (dataReuniao === dataAmanha) {
      filtrados.push({
        json: {
          ...lead,
          telefonePadronizado: ajustarTelefone(telefone),
          motivo: "reuniao_amanha" // Use isso no Switch para mandar msg de "é amanhã"
        }
      });
    }
  }

  return filtrados;
}

// ========================================
// CASO 1 → Execução das 9h (gatilho = "9h")
// ========================================
if (gatilho === "9h") {
  const agora = new Date();
  const hoje = agora.toISOString().split("T")[0];

  for (const item of items) {
    const lead = item.json;
    const telefone = lead.telefone;
  const reuniao = lead.reuniao_data;

    if (!reuniao) continue;

    const dataReuniao = reuniao.split("T")[0];

    if (dataReuniao === hoje) {
      filtrados.push({
        json: {
          ...lead,
          telefonePadronizado: ajustarTelefone(telefone),
          motivo: "reuniao_hoje"
        }
      });
    }
  }

  return filtrados;
}

// ========================================
// CASO 2 → Execução dos 21/51 min (10 min antes)
// ========================================
const agoraUTC = Date.now();
const min7 = agoraUTC + 7 * 60 * 1000;
const min12 = agoraUTC + 12 * 60 * 1000;

for (const item of items) {
  const lead = item.json;
  const telefone = lead.telefone;
  const reuniao = lead.reuniao_data;

  if (!reuniao) continue;

  const timestampReuniao = new Date(reuniao).getTime();

  if (timestampReuniao >= min7 && timestampReuniao <= min12) {
    filtrados.push({
      json: {
        ...lead,
        telefonePadronizado: ajustarTelefone(telefone),
        motivo: "reuniao_proximos_10min"
      }
    });
  }
}

return filtrados;

// ==========================
// 1. DEFINIÇÃO DOS TEMPLATES
// ==========================
const templates = {

  // ---------- 10 MIN ANTES ----------
  reminder_reuniao: {
    name: "reminder_reuniao",
    vars: 2,
    text:
`Olá, {{1}}!

Passando apenas para lembrar que nossa reunião terá início em aproximadamente 10 minutos.

Segue novamente o link de acesso para facilitar:

{{2}}

Até daqui a pouco!`
  },

  reminder_reuniao_sem_link: {
    name: "reminder_reuniao_sem_link",
    vars: 1,
    text:
`Olá, {{1}}!

Passando apenas para lembrar que nossa reunião terá início em aproximadamente 10 minutos.

Nos vemos em instantes!`
  },

  // ---------- HOJE ----------
  reminder_reuniao2: {
    name: "reminder_reuniao2",
    vars: 3,
    text:
`Bom dia, {{1}}!

Passando para lembrar da nossa reunião agendada para hoje às {{2}}.

Segue novamente o link de acesso:

{{3}}

Fico à disposição. Até mais tarde!`
  },

  reminder_reuniao_sem_link2: {
    name: "reminder_reuniao_sem_link2",
    vars: 2,
    text:
`Bom dia, {{1}}!

Passando para lembrar da nossa reunião agendada para hoje às {{2}}.

Nos vemos mais tarde.`
  },

  // ---------- AMANHÃ ----------
  reminder_reuniao_amanha: {
    name: "reminder_reuniao_amanha",
    vars: 2,
    text:
`Boa noite, {{1}}!

Passando apenas para confirmar nossa reunião agendada para amanhã às {{2}}.

Caso exista qualquer necessidade de ajuste no horário, por favor, me avise.

Até amanhã!`
  }

};

// ==========================
// 2. DADOS DO LEAD
// ==========================

const lead = items[0].json;

const nomeCompleto = lead.name || "Visitante";
const primeiroNome = nomeCompleto.trim().split(/\s+/)[0];

const telefone = String(lead.telefone);
const motivo = lead.motivo;

const linkReuniao = lead.link_meet || null;

const dataReuniao = lead.horario_reuniao;

let horarioFormatado = "";

if (dataReuniao) {
  horarioFormatado = new Intl.DateTimeFormat("pt-BR", {
    timeZone: "America/Sao_Paulo",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false
  }).format(new Date(dataReuniao));
}

// ==========================
// 3. ESCOLHER TEMPLATE
// ==========================

let templateEscolhido;

switch (motivo) {

  case "reuniao_amanha":
    templateEscolhido = templates.reminder_reuniao_amanha;
    break;

  case "reuniao_hoje":
    templateEscolhido = linkReuniao
      ? templates.reminder_reuniao2
      : templates.reminder_reuniao_sem_link2;
    break;

  case "reuniao_proximos_10min":
  default:
    templateEscolhido = linkReuniao
      ? templates.reminder_reuniao
      : templates.reminder_reuniao_sem_link;

}

// ==========================
// 4. PARAMETERS
// ==========================

const parameters = [];

parameters.push({
  type: "text",
  text: primeiroNome
});

if (motivo === "reuniao_amanha") {

  parameters.push({
    type: "text",
    text: horarioFormatado
  });

}

else if (motivo === "reuniao_hoje") {

  parameters.push({
    type: "text",
    text: horarioFormatado
  });

  if (linkReuniao) {

    parameters.push({
      type: "text",
      text: linkReuniao
    });

  }

}

else {

  if (linkReuniao) {

    parameters.push({
      type: "text",
      text: linkReuniao
    });

  }

}

// ==========================
// 5. PAYLOAD WHATSAPP
// ==========================

const body = {
  messaging_product: "whatsapp",
  to: telefone,
  type: "template",
  template: {
    name: templateEscolhido.name,
    language: {
      code: "pt_BR"
    },
    components: [
      {
        type: "body",
        parameters
      }
    ]
  }
};

// ==========================
// 6. PREVIEW
// ==========================

let preview = templateEscolhido.text;

preview = preview.replace("{{1}}", primeiroNome);

if (motivo === "reuniao_amanha") {

  preview = preview.replace("{{2}}", horarioFormatado);

}
else if (motivo === "reuniao_hoje") {

  preview = preview.replace("{{2}}", horarioFormatado);

  if (linkReuniao)
    preview = preview.replace("{{3}}", linkReuniao);

}
else {

  if (linkReuniao)
    preview = preview.replace("{{2}}", linkReuniao);

}

preview = preview.replace(/{{\d+}}/g, "");

// ==========================
// 7. MEMÓRIA REDIS
// ==========================

const redisMemoryMessage = JSON.stringify({
  type: "ai",
  data: {
    content: preview,
    tool_calls: [],
    invalid_tool_calls: [],
    additional_kwargs: {},
    response_metadata: {}
  }
});

// ==========================
// RETORNO
// ==========================

return [{
  json: {

    resultado_api: body,

    mensagem_visual: preview,

     redis_memory_message: redisMemoryMessage,

    template_name: templateEscolhido.name,

    motivo_disparo: motivo,

    lead_id: lead.id_lead,

    lead_nome: nomeCompleto,

    primeiro_nome: primeiroNome,

    telefone

  }
}];

